            if (nitSt === 'danger') { score -= 30; tips.push({ icon: '\u2620\uFE0F', text: 'CRITICAL: Nitrite at ' + waterChem.nitrite.toFixed(2) + ' ppm! Brown blood disease risk. Emergency water change!', color: 'text-red-600' }); }
            // Nitrate penalty
